package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.assertDoesNotThrow;
import static org.mockito.Mockito.doThrow;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.times;

import java.io.Flushable;
import java.io.IOException;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.Test;

class CSVPrinterFlushTest {

    @Test
    void flush_whenOutIsFlushable_flushCalled() throws IOException {
        Flushable flushable = mock(Flushable.class);
        CSVFormat format = mock(CSVFormat.class);
        CSVPrinter printer = new CSVPrinter(flushable, format);

        printer.flush();

        verify(flushable, times(1)).flush();
    }

    @Test
    void flush_whenOutIsNotFlushable_noException() {
        Appendable appendable = new Appendable() {
            @Override
            public Appendable append(CharSequence csq) {
                return this;
            }

            @Override
            public Appendable append(CharSequence csq, int start, int end) {
                return this;
            }

            @Override
            public Appendable append(char c) {
                return this;
            }
        };
        CSVFormat format = mock(CSVFormat.class);
        CSVPrinter printer = new CSVPrinter(appendable, format);

        assertDoesNotThrow(printer::flush);
    }

    @Test
    void flush_whenFlushThrowsIOException_exceptionPropagated() throws IOException {
        Flushable flushable = mock(Flushable.class);
        CSVFormat format = mock(CSVFormat.class);
        CSVPrinter printer = new CSVPrinter(flushable, format);
        doThrow(new IOException("flush failed")).when(flushable).flush();

        IOException thrown = null;
        try {
            printer.flush();
        } catch (IOException e) {
            thrown = e;
        }

        assert(thrown != null);
        assert("flush failed".equals(thrown.getMessage()));
    }
}
